    """
    A class that checks if a value is a valid phone number, optionally restricted to a specific country's
    formatting rules.
    """

    _delimiters_re = re.compile(r'[\s\-.()]')
    _generic_national_re = re.compile(r'\d{7,15}')
    _generic_international_re = re.compile(r'\+[1-9]\d{6,14}')

    _country_patterns = {
        'US': (re.compile(r'\d{10}'), re.compile(r'\+1\d{10}')),
        'GB': (re.compile(r'0\d{9,10}'), re.compile(r'\+44\d{9,10}')),
    }

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: ISO 3166-1 alpha-2 country code used to apply country-specific formatting rules, if omitted,
                any reasonably formatted phone number is accepted.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber()
        assert '555-123-4567' == IsPhoneNumber()
        assert 'not-a-phone-number' != IsPhoneNumber()
        assert 123 != IsPhoneNumber()

        assert '555-123-4567' == IsPhoneNumber('US')
        assert '+1-555-123-4567' == IsPhoneNumber('US')
        assert '15551234567' != IsPhoneNumber('US')
        assert '020 7946 0958' != IsPhoneNumber('US')

        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert '555-123-4567' != IsPhoneNumber('GB')

        assert '+33 1 42 68 53 00' == IsPhoneNumber('FR')
        ```
        """
        self.country = country
        super().__init__(repr(country) if country is not None else plain_repr('*'))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        cleaned = self._delimiters_re.sub('', other)
        if not cleaned:
            return False

        if self.country is None:
            if cleaned.startswith('+'):
                return bool(self._generic_international_re.fullmatch(cleaned))
            else:
                return bool(self._generic_national_re.fullmatch(cleaned))

        national_re, international_re = self._country_patterns.get(self.country.upper(), (None, None))
        if national_re is None:
            return cleaned.startswith('+') and bool(self._generic_international_re.fullmatch(cleaned))
        else:
            return bool(national_re.fullmatch(cleaned)) or bool(international_re.fullmatch(cleaned))


